### API Testing with Jest

```javascript
const request = require("supertest");
const app = require("../app");

describe("User API", () => {
  let authToken;
  let testUser;

  beforeAll(async () => {
    // Setup test database
    await setupTestDatabase();

    // Get auth token
    const authResponse = await request(app).post("/api/v1/auth/login").send({
      email: "test@example.com",
      password: "testpassword",
    });

    authToken = authResponse.body.token;
  });

  afterAll(async () => {
    await cleanupTestDatabase();
  });

  describe("GET /api/v1/users", () => {
    test("should return paginated users list", async () => {
      const response = await request(app)
        .get("/api/v1/users?page=1&limit=10")
        .set("Authorization", `Bearer ${authToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("data");
      expect(response.body).toHaveProperty("pagination");
      expect(response.body.data).toBeInstanceOf(Array);
      expect(response.body.pagination).toMatchObject({
        page: 1,
        limit: 10,
        total: expect.any(Number),
        pages: expect.any(Number),
      });
    });

    test("should filter users by search term", async () => {
      const response = await request(app)
        .get("/api/v1/users?search=john")
        .set("Authorization", `Bearer ${authToken}`)
        .expect(200);

      response.body.data.forEach((user) => {
        expect(
          user.name.toLowerCase().includes("john") ||
            user.email.toLowerCase().includes("john"),
        ).toBe(true);
      });
    });
  });

  describe("POST /api/v1/users", () => {
    test("should create user with valid data", async () => {
      const userData = {
        name: "Test User",
        email: "newuser@example.com",
        password: "SecurePass123!",
      };

      const response = await request(app)
        .post("/api/v1/users")
        .set("Authorization", `Bearer ${authToken}`)
        .send(userData)
        .expect(201);

      expect(response.body.data).toMatchObject({
        name: userData.name,
        email: userData.email,
        id: expect.any(Number),
        createdAt: expect.any(String),
      });

      expect(response.body.data).not.toHaveProperty("password");
      testUser = response.body.data;
    });

    test("should reject invalid email", async () => {
      const response = await request(app)
        .post("/api/v1/users")
        .set("Authorization", `Bearer ${authToken}`)
        .send({
          name: "Test User",
          email: "invalid-email",
          password: "SecurePass123!",
        })
        .expect(400);

      expect(response.body.error).toBe("Validation failed");
      expect(response.body.details).toEqual(
        expect.arrayContaining([
          expect.objectContaining({
            msg: expect.stringContaining("email"),
          }),
        ]),
      );
    });
  });
});
