    const schema = z.object({
      email: z.string().email(),
      password: z.string().min(8),
      firstName: z.string().min(2),
      lastName: z.string().min(2),
    });

    try {
      schema.parse(userData);
    } catch (error) {
      throw new ValidationError("Invalid user data", error.errors);
    }
  }
