// Custom hooks for data fetching with caching
import { useState, useEffect, useCallback, useRef } from 'react';

interface UseApiOptions<T> {
    initialData?: T;
    dependencies?: any[];
    cacheKey?: string;
    ttl?: number;
}

interface ApiState<T> {
    data: T | null;
    loading: boolean;
    error: Error | null;
    refetch: () => Promise<void>;
}

const cache = new Map<string, { data: any; timestamp: number; ttl: number }>();

export function useApi<T>(
    fetcher: () => Promise<T>,
    options: UseApiOptions<T> = {}
): ApiState<T> {
    const { initialData = null, dependencies = [], cacheKey, ttl = 300000 } = options;

    const [state, setState] = useState<Omit<ApiState<T>, 'refetch'>>({
        data: initialData,
        loading: false,
        error: null
    });

    const fetcherRef = useRef(fetcher);
    fetcherRef.current = fetcher;

    const fetchData = useCallback(async () => {
        // Check cache first
        if (cacheKey) {
            const cached = cache.get(cacheKey);
            if (cached && Date.now() - cached.timestamp < cached.ttl) {
                setState(prev => ({ ...prev, data: cached.data, loading: false }));
                return;
            }
        }

        setState(prev => ({ ...prev, loading: true, error: null }));

        try {
            const data = await fetcherRef.current();

            // Cache the result
            if (cacheKey) {
                cache.set(cacheKey, { data, timestamp: Date.now(), ttl });
            }

            setState({ data, loading: false, error: null });
        } catch (error) {
            setState(prev => ({
                ...prev,
                loading: false,
                error: error instanceof Error ? error : new Error(String(error))
            }));
        }
    }, [cacheKey, ttl]);

    useEffect(() => {
        fetchData();
    }, dependencies);

    return {
        ...state,
        refetch: fetchData
    };
}

// Higher-order component for error boundaries
interface ErrorBoundaryState {
    hasError: boolean;
    error?: Error;
}

class ErrorBoundary extends React.Component<
    React.PropsWithChildren<{
        fallback?: React.ComponentType<{ error: Error; retry: () => void }>;
        onError?: (error: Error, errorInfo: React.ErrorInfo) => void;
    }>,
    ErrorBoundaryState
> {
    constructor(props: any) {
        super(props);
        this.state = { hasError: false };
    }

    static getDerivedStateFromError(error: Error): ErrorBoundaryState {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
        this.props.onError?.(error, errorInfo);
    }

    retry = () => {
        this.setState({ hasError: false, error: undefined });
    };

    render() {
        if (this.state.hasError) {
            const FallbackComponent = this.props.fallback || DefaultErrorFallback;
            return <FallbackComponent error={this.state.error!} retry={this.retry} />;
        }

        return this.props.children;
    }
}

const DefaultErrorFallback: React.FC<{ error: Error; retry: () => void }> = ({ error, retry }) => (
    <div className="error-boundary">
        <h2>Something went wrong</h2>
        <details>
            <summary>Error details</summary>
            <pre>{error.message}</pre>
        </details>
        <button onClick={retry}>Try again</button>
    </div>
);

