// app/actions/posts.ts
"use server";

import { z } from "zod";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { db } from "@/lib/db";
import { getCurrentUser } from "@/lib/auth";
import { ratelimit } from "@/lib/rate-limit";

const createPostSchema = z.object({
  title: z.string().min(5).max(200),
  content: z.string().min(10).max(10000),
  tags: z.array(z.string()).max(5),
});

export async function createPost(formData: FormData) {
  // Authentication check
  const user = await getCurrentUser();
  if (!user) {
    return { error: "Unauthorized" };
  }

  // Rate limiting
  const { success } = await ratelimit.limit(user.id);
  if (!success) {
    return { error: "Too many requests. Please try again later." };
  }

  // Validate input
  const rawData = {
    title: formData.get("title"),
    content: formData.get("content"),
    tags: JSON.parse(formData.get("tags") as string),
  };

  const validation = createPostSchema.safeParse(rawData);
  if (!validation.success) {
    return {
      error: "Invalid input",
      fieldErrors: validation.error.flatten().fieldErrors,
    };
  }

  const { title, content, tags } = validation.data;

  try {
    // AI-suggested: Use transaction for atomicity
    const post = await db.$transaction(async (tx) => {
      // Create post
      const newPost = await tx.post.create({
        data: {
          title,
          content,
          authorId: user.id,
          published: false,
        },
      });

      // Create or connect tags
      for (const tagName of tags) {
        const tag = await tx.tag.upsert({
          where: { name: tagName },
          create: { name: tagName },
          update: {},
        });

        await tx.tagOnPost.create({
          data: {
            postId: newPost.id,
            tagId: tag.id,
          },
        });
      }

      return newPost;
    });

    // Revalidate relevant paths
    revalidatePath("/dashboard/posts");
    revalidatePath(`/posts/${post.id}`);

    return { success: true, postId: post.id };
  } catch (error) {
    console.error("Failed to create post:", error);
    return { error: "Failed to create post. Please try again." };
  }
}

export async function publishPost(postId: string) {
  const user = await getCurrentUser();
  if (!user) {
    return { error: "Unauthorized" };
  }

  try {
    // Verify ownership
    const post = await db.post.findUnique({
      where: { id: postId },
      select: { authorId: true },
    });

    if (!post || post.authorId !== user.id) {
      return { error: "Post not found or unauthorized" };
    }

    // Publish
    await db.post.update({
      where: { id: postId },
      data: { published: true },
    });

    revalidatePath(`/posts/${postId}`);
    redirect(`/posts/${postId}`);
  } catch (error) {
    console.error("Failed to publish post:", error);
    return { error: "Failed to publish post" };
  }
}
